.login-container {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  min-height: 100vh;
  background: linear-gradient(135deg, #667eea 0%, #764ba2 25%, #f093fb 50%, #4facfe 75%, #00f2fe 100%);
  padding: 24px;
  position: relative;
  overflow: hidden;
}

.login-card {
  max-width: 460px;
  width: 100%;
  padding: 30px 30px;
  border-radius: 20px !important;
  background: rgba(255, 255, 255, 0.98);
  backdrop-filter: blur(10px);
  box-shadow: 0 25px 60px rgba(102, 126, 234, 0.35),
              0 0 1px rgba(255, 107, 197, 0.5) !important;
  border: 1px solid rgba(255, 255, 255, 0.7);
  position: relative;
  z-index: 10;

  mat-card-header {
    display: flex;
    flex-direction: column;
    align-items: center;
    margin-bottom: 30px;

    mat-card-title {
      font-size: 28px;
      font-weight: 800;
      background: linear-gradient(135deg, #667eea 0%, #764ba2 50%, #f093fb 100%);
      -webkit-background-clip: text;
      -webkit-text-fill-color: transparent;
      background-clip: text;
    }

    mat-card-subtitle {
      font-size: 14px;
      margin-top: 8px;
      background: linear-gradient(135deg, #764ba2 0%, #4facfe 100%);
      -webkit-background-clip: text;
      -webkit-text-fill-color: transparent;
      background-clip: text;
      font-weight: 600;
    }
  }
}

.full-width {
  width: 100%;
}

.brand-pill {
  width: fit-content;
  margin: 0 auto 10px;
  padding: 8px 16px;
  border-radius: 999px;
  font-size: 12px;
  font-weight: 700;
  color: white;
  background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
  box-shadow: 0 4px 15px rgba(102, 126, 234, 0.4);
  text-transform: uppercase;
  letter-spacing: 0.5px;
}

.submit-btn {
  height: 50px;
  margin-top: 20px;
  font-size: 16px;
  border-radius: 10px !important;
  font-weight: 700;
  background: linear-gradient(135deg, #667eea 0%, #764ba2 50%, #f093fb 100%) !important;
  color: white !important;
  box-shadow: 0 8px 25px rgba(102, 126, 234, 0.35) !important;
  text-transform: uppercase;
  letter-spacing: 1px;
  transition: all 0.3s ease !important;

  &:hover:not(:disabled) {
    transform: translateY(-2px);
    box-shadow: 0 12px 35px rgba(102, 126, 234, 0.5) !important;
  }

  &:disabled {
    opacity: 0.7;
  }
}

mat-card-actions {
  padding: 20px 0 0;
  text-align: center;
  border-top: 1px solid #e5e7eb;

  p {
    margin: 0;
    background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
    background-clip: text;
    font-weight: 600;
  }

  a {
    color: #f093fb;
    text-decoration: none;
    font-weight: 700;

    &:hover {
      text-decoration: underline;
    }
  }
}

.demo-accounts {
  margin-top: 25px;
  padding: 20px;
  background: rgba(255, 255, 255, 0.95);
  border-radius: 12px;
  box-shadow: 0 10px 30px rgba(102, 126, 234, 0.25);
  max-width: 460px;
  width: 100%;
  position: relative;
  z-index: 10;
  border: 1px solid rgba(240, 147, 251, 0.2);

  h4 {
    margin: 0 0 15px;
    background: linear-gradient(135deg, #667eea 0%, #f093fb 100%);
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
    background-clip: text;
    font-size: 16px;
    text-align: center;
    font-weight: 700;
  }

  p {
    margin: 8px 0;
    font-size: 13px;
    color: #374151;
    display: flex;
    justify-content: space-between;
    padding: 12px 14px;
    background: linear-gradient(135deg, rgba(102, 126, 234, 0.08) 0%, rgba(240, 147, 251, 0.08) 100%);
    border-radius: 8px;
    border-left: 3px solid #667eea;
    transition: all 0.3s ease;

    &:hover {
      background: linear-gradient(135deg, rgba(102, 126, 234, 0.12) 0%, rgba(240, 147, 251, 0.12) 100%);
      transform: translateX(4px);
    }

    strong {
      background: linear-gradient(135deg, #667eea 0%, #f093fb 100%);
      -webkit-background-clip: text;
      -webkit-text-fill-color: transparent;
      background-clip: text;
      font-weight: 700;
    }
  }
}

.page-header {
  margin-bottom: 30px;

  h1 {
    display: flex;
    align-items: center;
    gap: 12px;
    margin: 0;
    font-size: 28px;

    mat-icon {
      color: #3f51b5;
      font-size: 32px;
      width: 32px;
      height: 32px;
    }
  }

  .subtitle {
    color: #666;
    margin: 8px 0 0;
    font-size: 14px;
  }
}

.loading {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  padding: 60px;

  p {
    margin-top: 20px;
    color: #666;
  }
}

.error-message {
  display: flex;
  flex-direction: column;
  align-items: center;
  padding: 40px;
  background: #ffebee;
  border-radius: 12px;
  text-align: center;

  mat-icon {
    font-size: 48px;
    width: 48px;
    height: 48px;
    color: #f44336;
  }

  p {
    color: #c62828;
    margin: 15px 0;
  }
}

.stats-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(200px, 1fr));
  gap: 20px;
  margin-bottom: 30px;
}

.stat-card {
  display: flex;
  flex-direction: column;
  align-items: center;
  padding: 25px 20px;
  text-align: center;
  transition: transform 0.2s, box-shadow 0.2s;

  &:hover {
    transform: translateY(-4px);
    box-shadow: 0 8px 25px rgba(0,0,0,0.12);
  }

  mat-icon {
    font-size: 36px;
    width: 36px;
    height: 36px;
    color: #3f51b5;
    margin-bottom: 10px;
  }

  h2 {
    font-size: 32px;
    margin: 0;
    background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
    background-clip: text;
  }

  p {
    margin: 8px 0 0;
    color: #666;
    font-size: 13px;
  }

  &.users mat-icon { color: #3f51b5; }
  &.brands mat-icon { color: #7b1fa2; }
  &.influencers mat-icon { color: #2e7d32; }
  &.earnings mat-icon { color: #ff9800; }
}

section {
  background: white;
  border-radius: 12px;
  padding: 25px;
  margin-bottom: 30px;
  box-shadow: 0 2px 8px rgba(0,0,0,0.08);
}

.section-header {
