}

.filter-dropdown {
  min-width: 180px;

  ::ng-deep .mat-mdc-form-field-subscript-wrapper {
    display: none;
  }
}

.table-container {
  overflow-x: auto;
}

.full-width {
  width: 100%;
}

table {
  th {
    font-weight: 600;
    color: #333;
